@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h2 class="mb-3">Project Board</h2>

@if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">@errorMessage</div>
}

@if (isLoading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (allTasks is not null)
{
    <!-- Stats Bar -->
    <div class="row g-2 mb-3">
        <div class="col">
            <div class="card text-center">
                <div class="card-body py-2">
                    <div class="fw-bold">Total</div>
                    <div class="fs-4">@allTasks.Count</div>
                </div>
            </div>
        </div>
        @foreach (var col in Columns)
        {
            <div class="col">
                <div class="card text-center">
                    <div class="card-body py-2">
                        <div class="fw-bold">@col</div>
                        <div class="fs-4">@allTasks.Count(t => t.Status == col)</div>
                    </div>
                </div>
            </div>
        }
        <div class="col">
            <div class="card text-center border-danger">
                <div class="card-body py-2">
                    <div class="fw-bold text-danger">Overdue</div>
                    <div class="fs-4 text-danger">@allTasks.Count(t => t.DueDate < DateTime.Today)</div>
                </div>
            </div>
        </div>
    </div>

    <!-- Search Bar -->
    <div class="mb-3">
        <input type="text" class="form-control" placeholder="Search tasks by title..."
               @bind="searchQuery" @bind:event="oninput" />
    </div>

    <!-- Kanban Columns -->
    <div class="row g-3">
        @for (int i = 0; i < Columns.Length; i++)
        {
            var colIndex = i;
            var colName = Columns[colIndex];
            var colTasks = FilteredTasks.Where(t => t.Status == colName).ToList();

            <div class="col-md-4">
                <div class="card h-100">
                    <div class="card-header d-flex justify-content-between align-items-center">
                        <strong>@colName</strong>
                        <span class="badge bg-secondary">@colTasks.Count</span>
                    </div>
                    <div class="card-body d-flex flex-column gap-2 overflow-auto" style="min-height: 200px;">
                        @foreach (var task in colTasks)
                        {
                            var taskColIndex = colIndex;
                            <div class="card shadow-sm">
                                <div class="card-body p-2">
                                    <div class="fw-semibold mb-1">@task.Title</div>
                                    <div class="text-muted small mb-1">@task.Assignee</div>
                                    <div class="d-flex justify-content-between align-items-center mb-1">
                                        <span class="badge @GetPriorityClass(task.Priority)">@task.Priority</span>
                                        <span class="small text-muted">@task.DueDate.ToString("MMM dd")</span>
                                    </div>
                                    <div class="d-flex justify-content-between mt-1">
                                        @if (taskColIndex > 0)
                                        {
                                            <button class="btn btn-outline-secondary btn-sm"
                                                    @onclick="() => MoveTaskAsync(task.Id, Columns[taskColIndex - 1])">
                                                &larr; Move Left
                                            </button>
                                        }
                                        else
                                        {
                                            <span></span>
                                        }
                                        @if (taskColIndex < Columns.Length - 1)
                                        {
                                            <button class="btn btn-outline-secondary btn-sm"
                                                    @onclick="() => MoveTaskAsync(task.Id, Columns[taskColIndex + 1])">
                                                Move Right &rarr;
                                            </button>
                                        }
                                    </div>
                                </div>
                            </div>
                        }
                    </div>
                    <div class="card-footer">
                        @if (addingToColumn == colName)
                        {
                            <div class="d-flex flex-column gap-2">
                                <input type="text" class="form-control form-control-sm" placeholder="Title"
                                       @bind="newTitle" />
                                <input type="text" class="form-control form-control-sm" placeholder="Assignee"
                                       @bind="newAssignee" />
                                <select class="form-select form-select-sm" @bind="newPriority">
                                    <option value="High">High</option>
                                    <option value="Medium">Medium</option>
                                    <option value="Low">Low</option>
                                </select>
                                <input type="date" class="form-control form-control-sm" @bind="newDueDate" />
                                <div class="d-flex gap-2">
                                    <button class="btn btn-primary btn-sm flex-fill"
                                            @onclick="() => SaveTaskAsync(colName)" disabled="@isSaving">
                                        Save
                                    </button>
                                    <button class="btn btn-outline-secondary btn-sm flex-fill"
                                            @onclick="CancelAdd" disabled="@isSaving">
                                        Cancel
                                    </button>
                                </div>
                            </div>
                        }
                        else
                        {
                            <button class="btn btn-outline-primary btn-sm w-100"
                                    @onclick="() => StartAdd(colName)">
                                + Add Task
                            </button>
                        }
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    private static readonly string[] Columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem>? allTasks;
    private bool isLoading = true;
    private string? errorMessage;
    private string searchQuery = string.Empty;

    // Add-task form state
    private string? addingToColumn;
    private string newTitle = string.Empty;
    private string newAssignee = string.Empty;
    private string newPriority = "Medium";
    private DateTime newDueDate = DateTime.Today.AddDays(7);
    private bool isSaving;

    private IEnumerable<TaskItem> FilteredTasks =>
        string.IsNullOrWhiteSpace(searchQuery)
            ? allTasks!
            : allTasks!.Where(t => t.Title.Contains(searchQuery, StringComparison.OrdinalIgnoreCase));

    protected override async Task OnInitializedAsync()
    {
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task MoveTaskAsync(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var task = allTasks!.First(t => t.Id == taskId);
            allTasks![allTasks.IndexOf(task)] = task with { Status = newStatus };
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private void StartAdd(string column)
    {
        addingToColumn = column;
        newTitle = string.Empty;
        newAssignee = string.Empty;
        newPriority = "Medium";
        newDueDate = DateTime.Today.AddDays(7);
    }

    private void CancelAdd() => addingToColumn = null;

    private async Task SaveTaskAsync(string column)
    {
        if (string.IsNullOrWhiteSpace(newTitle))
            return;

        isSaving = true;
        try
        {
            var created = await TaskService.CreateTaskAsync(newTitle.Trim(), newAssignee.Trim(), newPriority, newDueDate);
            // The service creates with default status; update to the target column if different
            if (created.Status != column)
            {
                await TaskService.UpdateTaskStatusAsync(created.Id, column);
                created = created with { Status = column };
            }
            allTasks!.Add(created);
            addingToColumn = null;
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
        finally
        {
            isSaving = false;
        }
    }

    private static string GetPriorityClass(string priority) => priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };
}

